:root {
  --background: light-dark(
    oklch(100% 0.00011 271.152),
    oklch(18.22% 0.00002 271.152)
  );
  --foreground: light-dark(
    oklch(18.22% 0.00002 271.152),
    oklch(98.511% 0.00011 271.152)
  );
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  color-scheme: light dark;
}

body {
  margin: 0;
  padding: 0;
  height: 100vh;
  width: 100%;
  background-color: var(--background);
  display: flex;
  justify-content: center;
  align-items: center;
}

p {
  font-size: 1.5rem;
}

.trailer {
  position: fixed;
  width: 8px;
  height: 8px;
  background-color: var(--foreground);
  border-radius: 50%;
  left: 0;
  top: 0;
  transform: translate(-50%, -50%);
  pointer-events: none;
  z-index: 1000;
}

.trailer-outline {
  position: fixed;
  left: 0;
  top: 0;
  transform: translate(-50%, -50%);
  width: 80px;
  height: 80px;
  border: 2px solid var(--foreground);
  border-radius: 50%;
  pointer-events: none;
  z-index: 1000;
}

const trailer = document.getElementById("trailer");

const trailerOutline = document.createElement("div");
trailerOutline.className = "trailer-outline";
document.body.appendChild(trailerOutline);

document.body.onpointermove = (e) => {
  const { clientX, clientY } = e;

  trailer.animate(
    {
      left: `${clientX}px`,
      top: `${clientY}px`,
    },
    {
      duration: 1000,
      fill: "forwards",
    },
  );

  trailerOutline.animate(
    {
      left: `${clientX}px`,
      top: `${clientY}px`,
    },
    {
      duration: 3000,
      fill: "forwards",
    },
  );
};
